import{_ as a,c as i,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Registro de Cambios: Actualizaciones de Funciones | OpenSkills","description":"Consulta el historial de cambios de versiones de OpenSkills. Conoce las nuevas funciones como el comando update, enlaces simbólicos, repositorios privados, así como mejoras importantes como la protección contra recorrido de rutas y correcciones de problemas.","frontmatter":{"title":"Registro de Cambios: Actualizaciones de Funciones | OpenSkills","sidebarTitle":"Conoce las Novedades","subtitle":"Registro de Cambios: Actualizaciones de Funciones | OpenSkills","description":"Consulta el historial de cambios de versiones de OpenSkills. Conoce las nuevas funciones como el comando update, enlaces simbólicos, repositorios privados, así como mejoras importantes como la protección contra recorrido de rutas y correcciones de problemas.","tags":["changelog","historial de versiones"],"order":1},"headers":[],"relativePath":"es/numman-ali/openskills/changelog/changelog/index.md","filePath":"es/numman-ali/openskills/changelog/changelog/index.md"}'),r={name:"es/numman-ali/openskills/changelog/changelog/index.md"};function l(n,e,d,t,c,u){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="registro-de-cambios" tabindex="-1">Registro de Cambios <a class="header-anchor" href="#registro-de-cambios" aria-label="Permalink to &quot;Registro de Cambios&quot;">​</a></h1><p>Esta página documenta el historial de cambios de versiones de OpenSkills, ayudándote a comprender las nuevas funciones, mejoras y correcciones de problemas de cada versión.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="nuevas-funciones" tabindex="-1">Nuevas Funciones <a class="header-anchor" href="#nuevas-funciones" aria-label="Permalink to &quot;Nuevas Funciones&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Actualiza las habilidades instaladas desde las fuentes registradas (por defecto: actualiza todas)</li><li><strong>Seguimiento de Metadatos de Origen</strong> - Ahora se registra información de origen durante la instalación para actualizar las habilidades de manera confiable</li></ul><h3 id="mejoras" tabindex="-1">Mejoras <a class="header-anchor" href="#mejoras" aria-label="Permalink to &quot;Mejoras&quot;">​</a></h3><ul><li><strong>Lectura de Múltiples Habilidades</strong> - El comando <code>openskills read</code> ahora admite una lista de nombres de habilidades separados por comas</li><li><strong>Generación de Instrucciones de Uso</strong> - Optimizado el mensaje de invocación del comando read en entornos shell</li><li><strong>README</strong> - Añadida guía de actualización e indicaciones de uso manual</li></ul><h3 id="correcciones-de-errores" tabindex="-1">Correcciones de Errores <a class="header-anchor" href="#correcciones-de-errores" aria-label="Permalink to &quot;Correcciones de Errores&quot;">​</a></h3><ul><li><strong>Optimización de Experiencia de Actualización</strong> - Omite habilidades sin metadatos de origen y lista estas habilidades para indicar reinstalación</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="mejoras-1" tabindex="-1">Mejoras <a class="header-anchor" href="#mejoras-1" aria-label="Permalink to &quot;Mejoras&quot;">​</a></h3><ul><li><strong>README</strong> - Clarificado el método de instalación predeterminado local del proyecto, eliminado el mensaje de sincronización redundante</li><li><strong>Mensajes de Instalación</strong> - El instalador ahora distingue claramente entre la instalación predeterminada local del proyecto y la opción <code>--global</code></li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="mejoras-2" tabindex="-1">Mejoras <a class="header-anchor" href="#mejoras-2" aria-label="Permalink to &quot;Mejoras&quot;">​</a></h3><ul><li><strong>Documentación y Guía AGENTS.md</strong> - Todos los ejemplos de comandos e instrucciones de uso generadas ahora usan <code>npx openskills</code> de manera uniforme</li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="correcciones-de-errores-1" tabindex="-1">Correcciones de Errores <a class="header-anchor" href="#correcciones-de-errores-1" aria-label="Permalink to &quot;Correcciones de Errores&quot;">​</a></h3><ul><li><strong>Instalación en Windows</strong> - Corregido el problema de validación de ruta en sistemas Windows (&quot;Security error: Installation path outside target directory&quot;)</li><li><strong>Versión CLI</strong> - <code>npx openskills --version</code> ahora lee correctamente el número de versión de package.json</li><li><strong>SKILL.md en Directorio Raíz</strong> - Corregido el problema de instalación de repositorios de habilidades individuales con SKILL.md en el directorio raíz</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="nuevas-funciones-1" tabindex="-1">Nuevas Funciones <a class="header-anchor" href="#nuevas-funciones-1" aria-label="Permalink to &quot;Nuevas Funciones&quot;">​</a></h3><ul><li><p><strong>Soporte de Enlaces Simbólicos</strong> - Las habilidades ahora pueden instalarse en el directorio de habilidades mediante enlaces simbólicos (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>Admite actualizaciones de habilidades basadas en git mediante la creación de enlaces simbólicos desde repositorios clonados</li><li>Admite flujos de trabajo de desarrollo local de habilidades</li><li>Los enlaces simbólicos dañados se omiten elegantemente</li></ul></li><li><p><strong>Ruta de Salida Configurable</strong> - El comando sync añade la opción <code>--output</code> / <code>-o</code> (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>Puede sincronizarse a cualquier archivo <code>.md</code> (como <code>.ruler/AGENTS.md</code>)</li><li>Si el archivo no existe, crea automáticamente el archivo y añade el título</li><li>Crea automáticamente directorios anidados si es necesario</li></ul></li><li><p><strong>Instalación desde Ruta Local</strong> - Admite la instalación de habilidades desde directorios locales (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>Admite rutas absolutas (<code>/path/to/skill</code>)</li><li>Admite rutas relativas (<code>./skill</code>, <code>../skill</code>)</li><li>Admite expansión de tilde (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>Soporte de Repositorios Git Privados</strong> - Admite la instalación de habilidades desde repositorios privados (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>URLs SSH (<code>git@github.com:org/private-skills.git</code>)</li><li>URLs HTTPS con autenticación</li><li>Usa automáticamente las claves SSH del sistema</li></ul></li><li><p><strong>Suite de Pruebas Completa</strong> - 88 pruebas en 6 archivos de prueba</p><ul><li>Pruebas unitarias de detección de enlaces simbólicos, análisis YAML</li><li>Pruebas de integración de comandos install, sync</li><li>Pruebas de extremo a extremo del flujo de trabajo completo de CLI</li></ul></li></ul><h3 id="mejoras-3" tabindex="-1">Mejoras <a class="header-anchor" href="#mejoras-3" aria-label="Permalink to &quot;Mejoras&quot;">​</a></h3><ul><li><p><strong>La bandera <code>--yes</code> ahora omite todos los avisos</strong> - Modo completamente no interactivo, adecuado para CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>No solicita confirmación al sobrescribir habilidades existentes</li><li>Muestra el mensaje <code>Overwriting: &lt;skill-name&gt;</code> al omitir avisos</li><li>Todos los comandos ahora pueden ejecutarse en entornos sin interfaz</li></ul></li><li><p><strong>Reordenamiento del Flujo de Trabajo CI</strong> - Los pasos de construcción ahora se ejecutan antes que las pruebas</p><ul><li>Asegura que <code>dist/cli.js</code> exista para pruebas de extremo a extremo</li></ul></li></ul><h3 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h3><ul><li><strong>Protección contra Recorrido de Rutas</strong> - Verifica que la ruta de instalación se mantenga dentro del directorio de destino</li><li><strong>Desreferenciación de Enlaces Simbólicos</strong> - <code>cpSync</code> usa <code>dereference: true</code> para copiar de manera segura los destinos de enlaces simbólicos</li><li><strong>Regex YAML No Codicioso</strong> - Previene posibles ataques ReDoS en el análisis de frontmatter</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="correcciones-de-errores-2" tabindex="-1">Correcciones de Errores <a class="header-anchor" href="#correcciones-de-errores-2" aria-label="Permalink to &quot;Correcciones de Errores&quot;">​</a></h3><ul><li>Limpieza de documentación README - Eliminadas secciones duplicadas y marcas incorrectas</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="nuevas-funciones-2" tabindex="-1">Nuevas Funciones <a class="header-anchor" href="#nuevas-funciones-2" aria-label="Permalink to &quot;Nuevas Funciones&quot;">​</a></h3><ul><li>Bandera <code>--universal</code>, instala habilidades en <code>.agent/skills/</code> en lugar de <code>.claude/skills/</code><ul><li>Aplicable a entornos de múltiples agentes (Claude Code + Cursor/Windsurf/Aider)</li><li>Evita conflictos con el complemento del mercado nativo de Claude Code</li></ul></li></ul><h3 id="mejoras-4" tabindex="-1">Mejoras <a class="header-anchor" href="#mejoras-4" aria-label="Permalink to &quot;Mejoras&quot;">​</a></h3><ul><li>La instalación local del proyecto ahora es la opción predeterminada (anteriormente era instalación global)</li><li>Las habilidades se instalan por defecto en <code>./.claude/skills/</code></li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="nuevas-funciones-3" tabindex="-1">Nuevas Funciones <a class="header-anchor" href="#nuevas-funciones-3" aria-label="Permalink to &quot;Nuevas Funciones&quot;">​</a></h3><ul><li>README de una sola página completo con análisis técnico profundo</li><li>Comparación paralela con Claude Code</li></ul><h3 id="correcciones-de-errores-3" tabindex="-1">Correcciones de Errores <a class="header-anchor" href="#correcciones-de-errores-3" aria-label="Permalink to &quot;Correcciones de Errores&quot;">​</a></h3><ul><li>La etiqueta de ubicación ahora muestra correctamente <code>project</code> o <code>global</code> según la ubicación de instalación</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="nuevas-funciones-4" tabindex="-1">Nuevas Funciones <a class="header-anchor" href="#nuevas-funciones-4" aria-label="Permalink to &quot;Nuevas Funciones&quot;">​</a></h3><ul><li>Versión inicial</li><li><code>npx openskills install &lt;source&gt;</code> - Instala habilidades desde repositorios de GitHub</li><li><code>npx openskills sync</code> - Genera XML <code>&lt;available_skills&gt;</code> para AGENTS.md</li><li><code>npx openskills list</code> - Muestra las habilidades instaladas</li><li><code>npx openskills read &lt;name&gt;</code> - Carga el contenido de habilidades para agentes</li><li><code>npx openskills manage</code> - Eliminación interactiva de habilidades</li><li><code>npx openskills remove &lt;name&gt;</code> - Elimina una habilidad específica</li><li>Interfaz TUI interactiva para todos los comandos</li><li>Soporte para el formato SKILL.md de Anthropic</li><li>Divulgación progresiva (carga habilidades bajo demanda)</li><li>Soporte de recursos empaquetados (references/, scripts/, assets/)</li></ul><hr><h2 id="apendice-referencia-de-codigo-fuente" tabindex="-1">Apéndice: Referencia de Código Fuente <a class="header-anchor" href="#apendice-referencia-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia de Código Fuente&quot;">​</a></h2><details><summary><strong>Click para expandir y ver la ubicación del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta de Archivo</th></tr></thead><tbody><tr><td>Changelog Original</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const p=a(r,[["render",l]]);export{m as __pageData,p as default};
